// progressPercent converts playback position + duration (seconds) to an integer percent 0..100.
func progressPercent(position float64, duration int) int {
	if duration <= 0 || position <= 0 {
		return 0
	}
	pct := int((position / float64(duration)) * 100)
	if pct < 0 {
		return 0
	}
	if pct > 100 {
		return 100
	}
	return pct
}

